import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do you calculate the area of a circle?", a: "The area of a circle is A = pi x r^2, where r is the radius. Square the radius, then multiply by pi. For example, a circle with radius 5 has area pi x 25 = 78.54 square units." },
  { q: "What is the formula for the area of a triangle?", a: "The area of a triangle is A = (base x height) / 2. Multiply the base by the perpendicular height, then divide by two." },
  { q: "How do you find the area of a trapezoid?", a: "The trapezoid area formula is A = ((base 1 + base 2) / 2) x height. Add the two parallel bases, divide by two, and multiply by height." },
  { q: "What is the difference between area and perimeter?", a: "Area measures the space inside a shape and is expressed in square units. Perimeter measures the distance around the outside edge and is expressed in linear units." },
  { q: "How do you calculate the area of an irregular shape?", a: "Break the irregular shape into common shapes such as rectangles, triangles, and circles. Calculate each area separately, then add them together or subtract cut-out sections." },
];

type Shape = "square" | "rectangle" | "circle" | "triangle" | "trapezoid" | "ellipse" | "parallelogram";
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "0";

export default function AreaCalculator() {
  const [shape, setShape] = useState<Shape>("rectangle");
  const [side, setSide] = useState(5);
  const [length, setLength] = useState(8);
  const [width, setWidth] = useState(4);
  const [radius, setRadius] = useState(3);
  const [base, setBase] = useState(10);
  const [baseTwo, setBaseTwo] = useState(6);
  const [height, setHeight] = useState(5);
  const [major, setMajor] = useState(7);
  const [minor, setMinor] = useState(4);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (shape === "square") return { area: side ** 2, formula: "A = side^2", step: `A = ${side}^2 = ${fmt(side ** 2)}` };
    if (shape === "rectangle") return { area: length * width, formula: "A = length x width", step: `A = ${length} x ${width} = ${fmt(length * width)}` };
    if (shape === "circle") return { area: Math.PI * radius ** 2, formula: "A = pi x radius^2", step: `A = pi x ${radius}^2 = ${fmt(Math.PI * radius ** 2)}` };
    if (shape === "triangle") return { area: (base * height) / 2, formula: "A = (base x height) / 2", step: `A = (${base} x ${height}) / 2 = ${fmt((base * height) / 2)}` };
    if (shape === "trapezoid") return { area: ((base + baseTwo) / 2) * height, formula: "A = ((base 1 + base 2) / 2) x height", step: `A = ((${base} + ${baseTwo}) / 2) x ${height} = ${fmt(((base + baseTwo) / 2) * height)}` };
    if (shape === "ellipse") return { area: Math.PI * major * minor, formula: "A = pi x semi-major axis x semi-minor axis", step: `A = pi x ${major} x ${minor} = ${fmt(Math.PI * major * minor)}` };
    return { area: base * height, formula: "A = base x height", step: `A = ${base} x ${height} = ${fmt(base * height)}` };
  }, [shape, side, length, width, radius, base, baseTwo, height, major, minor]);

  const field = (id: string, label: string, value: number, setter: (value: number) => void) => (
    <div><label htmlFor={id} className="text-sm font-semibold text-foreground block mb-2">{label}</label><input id={id} type="number" min="0" step="0.01" inputMode="decimal" value={value} onChange={(event) => setter(Number(event.target.value))} className={inputClass} /></div>
  );

  return (
    <>
      <SEOHead title="Free Area Calculator Online - Calculate Area of Any Shape Instantly | CalcHive" description="Free online area calculator. Calculate area of square, rectangle, circle, triangle, trapezoid, ellipse and parallelogram instantly. 100% free for students and everyone, no signup required." canonical="/area-calculator" keywords="free area calculator, area calculator online free, calculate area of shapes free, rectangle area calculator free, circle area calculator free online" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Area Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free area calculator to calculate area of shapes free, including square, rectangle, circle, triangle, trapezoid, ellipse, and parallelogram.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-6"><label htmlFor="shape" className="text-sm font-semibold text-foreground block mb-2">Shape</label><select id="shape" value={shape} onChange={(event) => setShape(event.target.value as Shape)} className={inputClass}><option value="square">Square</option><option value="rectangle">Rectangle</option><option value="circle">Circle</option><option value="triangle">Triangle</option><option value="trapezoid">Trapezoid</option><option value="ellipse">Ellipse</option><option value="parallelogram">Parallelogram</option></select></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            {shape === "square" && field("side", "Side length", side, setSide)}
            {shape === "rectangle" && <>{field("length", "Length", length, setLength)}{field("width", "Width", width, setWidth)}</>}
            {shape === "circle" && field("radius", "Radius", radius, setRadius)}
            {shape === "triangle" && <>{field("base", "Base", base, setBase)}{field("height", "Height", height, setHeight)}</>}
            {shape === "trapezoid" && <>{field("base-one", "Base 1", base, setBase)}{field("base-two", "Base 2", baseTwo, setBaseTwo)}{field("height", "Height", height, setHeight)}</>}
            {shape === "ellipse" && <>{field("major", "Semi-major axis", major, setMajor)}{field("minor", "Semi-minor axis", minor, setMinor)}</>}
            {shape === "parallelogram" && <>{field("base", "Base", base, setBase)}{field("height", "Height", height, setHeight)}</>}
          </div>
          <motion.div key={`${shape}-${result.area}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Area</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-area">{fmt(result.area)}</p><p className="text-white/70 text-sm mt-1">square units</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Formula and steps</p><p className="text-sm text-foreground font-mono">{result.formula}</p><p className="text-sm text-foreground font-mono mt-1" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Area of Any Shape for Free</h2><p className="text-muted-foreground leading-relaxed">Select the shape, enter the dimensions, and this area calculator online free tool applies the matching formula instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">Area Formulas for Every Common Shape</h2><p className="text-muted-foreground leading-relaxed">Squares, rectangles, and parallelograms use side or base measurements. Circles and ellipses use pi, while triangles and trapezoids use base and height relationships.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Geometry Area Tool for Students and Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this rectangle area calculator free and circle area calculator free online for geometry homework, DIY planning, and everyday measurement checks.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/area-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


